function debounce(func, delay = 300) {
    let timeoutId = null;

    return function(...args) {
        // Clear the previous timer
        clearTimeout(timeoutId);

        // Set a new timer
        timeoutId = setTimeout(() => {
            func.apply(this, args);
        }, delay);
    };
}

